import React, { useRef, useEffect, useLayoutEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { SearchChatInput } from './SearchChatInput.js';
import { SearchChatPanel as DefaultSearchChatPanel } from './SearchChatPanel.js';
import { SearchResultsPanel as DefaultSearchResultsPanel } from './SearchResultsPanel.js';
import type { SearchResultsPanelProps } from './SearchResultsPanel.js';
import { SearchMobileResultsPanel as DefaultSearchMobileResultsPanel } from './SearchMobileResultsPanel.js';
import { SearchPrivacySettings } from './SearchPrivacySettings.js';
import { useComponent } from '../../hooks/useComponent.js';
import type { SearchPrivacySettingsProps } from './SearchPrivacySettings.js';
import { useIsMobile } from '../../hooks/useIsMobile.js';
import { useBodyScrollLock } from '../../hooks/useBodyScrollLock.js';
import { useFocusTrap } from '../../hooks/useFocusTrap.js';
import { useChatNavigation } from '../../hooks/useChatNavigation.js';
import { useMessageSources } from '../../hooks/useMessageSources.js';
import type { ChatMessage } from '../../types.js';

const DefaultAISearchIcon: React.FC = () => (
    <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 28 28" fill="none">
        <path d="M13.4162 4.66659C11.6858 4.66659 9.9936 5.17953 8.55474 6.14087C5.64375 8.08593 4.15199 11.6898 4.83485 15.1233C5.17248 16.8206 6.00488 18.3806 7.22857 19.6042C9.7041 22.0796 13.5307 22.8397 16.7647 21.5001C20.0002 20.1596 22.1662 16.919 22.1662 13.4166H24.4996C24.4996 15.0997 24.1068 16.7658 23.3755 18.2702C22.6929 19.6743 22.7219 21.4289 23.826 22.5327L26.3282 25.0343L25.0339 26.3285L22.5292 23.8238C21.4257 22.7204 19.6723 22.6936 18.2648 23.3677C14.1137 25.3557 8.92769 24.6027 5.57883 21.254C4.02886 19.704 2.97364 17.7289 2.54595 15.579C1.68088 11.23 3.57111 6.66428 7.25819 4.2006C9.08077 2.98288 11.2243 2.33325 13.4162 2.33325V4.66659Z" fill="#363B47"/>
        <path d="M18.3837 2.39022C18.4778 7.37676 19.4554 8.35378 24.4415 8.448C24.5146 9.02769 24.5146 9.63765 24.4415 10.2174C19.4557 10.3116 18.4779 11.2893 18.3837 16.2751C17.804 16.3482 17.1939 16.3483 16.6143 16.2751C16.5201 11.2891 15.5431 10.3115 10.5565 10.2174C10.4835 9.63771 10.4834 9.02763 10.5565 8.448C15.5433 8.35388 16.5202 7.37703 16.6143 2.39022C17.1939 2.31708 17.8041 2.31714 18.3837 2.39022Z" fill="#363B47"/>
    </svg>
);

export interface SearchUIProps {
    isOpen: boolean;
    onClose: () => void;
    onResetChat: () => void;
    onSubmit: (e: { preventDefault: () => void; _directQuery?: string }) => void;
    query: string;
    setQuery: (query: string) => void;
    messages: ChatMessage[];
    isLoading: boolean;
    conversationId?: string;
    isConversational?: boolean;
    onModeToggle?: () => void;
    trackProductClick?: (data: Record<string, unknown>) => void;
    trackCategoryClick?: (data: Record<string, unknown>) => void;
    trackContentClick?: (data: Record<string, unknown>) => void;
    pipelineStatus?: string;
    onIntentAnswer?: (answerText: string, answerId: string | number, options?: Record<string, unknown>) => void;
    onClarificationAnswer?: (answerText: string, optionId: string | number, paramName: string) => void;
    connectionStatus?: string;
    onRetryConnection?: () => void;
    reconnectInfo?: { attempt: number; maxAttempts: number; delayMs: number } | null;
    welcomeText?: string;
    seedQuestions?: string[];
    // DI props
    title?: string;
    subtitle?: string;
    searchIcon?: React.ReactNode;
    onModalOpen?: () => void;
    onModalClose?: () => void;
    aiSearchStoreUrl?: string;
    fallbackProductImage?: string;
    fallbackCategoryImage?: string;
    fallbackBlogImage?: string;
    fetchProductUrls: (skus: string[]) => Promise<Record<string, string>>;
    sessionId: string;
    onFeedbackSubmit?: (data: Record<string, unknown>) => Promise<unknown>;
    onOpenSupport?: () => void;
    /** URL for the support affordance; renders the control as a link when set. */
    supportHref?: string;
    /** Visible label for the support affordance. Defaults to "Talk to a specialist". */
    supportLabel?: string;
    privacyPolicyUrl?: string;
    FeedbackWidgetComponent?: React.ComponentType<{
        entityId: string;
        entityType: string;
        context: Record<string, unknown>;
    }>;
    defaultSearchExamples?: string[];
    consentEnabled?: boolean;
    onToggleConsent?: () => void;
    consentDisabled?: boolean;
    showProductTags?: boolean;
    /** How to display zero/null price: 'show' (default) | 'hide' | custom text */
    zeroPriceDisplay?: string;
    /** When true and the backend classifies intent === 'question', render Related Content before Products */
    relatedContentFirstForQuestions?: boolean;
    onScrollForMoreTapped?: (messageId: string) => void;
    onScrollStarted?: (messageId: string) => void;
    onInlineProductLinkClick?: (data: {
        sku: string;
        href: string;
        messageId?: string;
        queryContext: string;
    }) => void;
    /**
     * Render the initial (compact, no-messages) search state as a dropdown
     * anchored under a host element instead of a centered modal + backdrop.
     * Once a message is sent (conversation begins) it falls back to the modal.
     */
    anchored?: boolean;
    /** CSS selector for the host element to anchor the dropdown under (e.g. the search trigger box). */
    anchorSelector?: string;
    /**
     * Render the search in-flow (no modal overlay/backdrop/positioning) via a
     * portal into `inlineTarget`, instead of a centered/anchored modal. Used to
     * surface the `.omniguide-split-panel` inline beneath a host element (e.g.
     * the category-guide teaser's "ask a question").
     */
    inline?: boolean;
    /** Target element (or selector) the inline search portals into. */
    inlineTarget?: string | HTMLElement | null;
    /** Opt into the federated typeahead surface (SOI-708) in the compact instant panel. */
    typeahead?: boolean;
    /**
     * When true, hide the docked "Ask a question" chat input on the mobile
     * layout (SOI-757). Mobile only — the desktop input is unaffected.
     */
    hideMobileAskBox?: boolean;
    /** Placeholder for the mobile ask pill, e.g. "Ask a question about scopes…" (SOI-757). */
    mobileAskPlaceholder?: string;
}

export const SearchUI: React.FC<SearchUIProps> = ({
    isOpen,
    onClose,
    onResetChat,
    onSubmit,
    query: _query,
    setQuery,
    messages,
    isLoading,
    conversationId,
    trackProductClick,
    trackCategoryClick,
    trackContentClick,
    pipelineStatus = 'idle',
    onIntentAnswer,
    onClarificationAnswer,
    connectionStatus,
    onRetryConnection,
    reconnectInfo,
    welcomeText = '',
    seedQuestions = [],
    title = 'AI Search',
    subtitle = 'Shopping Advisor',
    searchIcon,
    anchored,
    anchorSelector,
    inline,
    inlineTarget,
    onModalOpen,
    onModalClose,
    aiSearchStoreUrl,
    fallbackProductImage,
    fallbackCategoryImage,
    fallbackBlogImage,
    fetchProductUrls,
    sessionId,
    onOpenSupport,
    supportHref,
    supportLabel = 'Talk to a specialist',
    privacyPolicyUrl = '/privacy-policy',
    FeedbackWidgetComponent,
    defaultSearchExamples,
    consentEnabled,
    onToggleConsent,
    consentDisabled,
    showProductTags,
    zeroPriceDisplay,
    relatedContentFirstForQuestions,
    onScrollForMoreTapped,
    onScrollStarted,
    typeahead,
    onInlineProductLinkClick,
    hideMobileAskBox = false,
    mobileAskPlaceholder,
}) => {
    const SearchChatPanel = useComponent('SearchChatPanel', DefaultSearchChatPanel);
    const SearchResultsPanel = useComponent('SearchResultsPanel', DefaultSearchResultsPanel);
    const SearchMobileResultsPanel = useComponent('SearchMobileResultsPanel', DefaultSearchMobileResultsPanel);

    const [isBottomSheetExpanded, setIsBottomSheetExpanded] = useState(true);
    const [closeButtonHovered, setCloseButtonHovered] = useState(false);
    const [liveQuery, setLiveQuery] = useState('');
    const mobileResultsRef = useRef<HTMLDivElement>(null);
    const modalRef = useRef<HTMLDivElement>(null);

    const isMobile = useIsMobile(768);
    // Anchored dropdown applies only to the initial (compact) state on desktop;
    // once a conversation starts it reverts to the centered modal. Inline mode
    // never uses the compact layout — it always renders the conversational
    // split-panel (answer + products columns), empty until the user asks.
    const isCompactMode = !inline && messages.length === 0;
    const anchoredActive = !!anchored && isOpen && isCompactMode && !isMobile;
    const [anchorStyle, setAnchorStyle] = useState<React.CSSProperties>({});
    // No body-scroll-lock or focus-trap for the anchored dropdown — it's not a
    // modal; the page stays interactive and focus can leave naturally.
    useBodyScrollLock(isOpen && !anchoredActive && !inline);
    useFocusTrap(isOpen && !anchoredActive && !inline, modalRef, '.omniguide-chip--gradient');

    const {
        qaPairs,
        currentMessageIndex,
        setMessageIndex,
    } = useChatNavigation({ messages, variant: 'search' });

    const { sources, messageId, queryContext, currentSectionIndex, intent } = useMessageSources(qaPairs, currentMessageIndex);

    // Notify on modal open/close
    useEffect(() => {
        if (isOpen) {
            onModalOpen?.();
        } else {
            onModalClose?.();
        }
        return () => {
            onModalClose?.();
        };
    }, [isOpen, onModalOpen, onModalClose]);

    // Anchored mode: take over the host search box. The panel sits on top of
    // the host box (top-aligned) and expands down into the suggestions, and the
    // host box is hidden so it reads as that box expanding — not a second field
    // below it. Repositions on scroll/resize; closes on outside click (no
    // backdrop to catch it). useLayoutEffect so it's positioned before paint.
    useLayoutEffect(() => {
        if (!anchoredActive || !anchorSelector) return;
        const anchor = document.querySelector<HTMLElement>(anchorSelector);
        if (!anchor) return;

        const MIN_WIDTH = 480;
        const MAX_WIDTH = 560;
        const EDGE = 8;
        const reposition = () => {
            const r = anchor.getBoundingClientRect();
            const width = Math.min(Math.max(r.width, MIN_WIDTH), MAX_WIDTH);
            // Right-aligned to the host box, clamped to the viewport.
            const left = Math.max(EDGE, Math.min(r.right - width, window.innerWidth - width - EDGE));
            // Top-aligned to the host box so the panel takes its place.
            setAnchorStyle({ top: Math.round(r.top), left: Math.round(left), width: Math.round(width) });
        };
        reposition();
        window.addEventListener('scroll', reposition, true);
        window.addEventListener('resize', reposition);

        // Hide the host box so there's one search field (the panel), not two.
        const prevVisibility = anchor.style.visibility;
        anchor.style.visibility = 'hidden';

        const onDocMouseDown = (e: MouseEvent) => {
            const target = e.target as Node;
            if (modalRef.current?.contains(target)) return;
            onClose();
        };
        document.addEventListener('mousedown', onDocMouseDown);

        return () => {
            window.removeEventListener('scroll', reposition, true);
            window.removeEventListener('resize', reposition);
            document.removeEventListener('mousedown', onDocMouseDown);
            anchor.style.visibility = prevVisibility;
        };
    }, [anchoredActive, anchorSelector, onClose]);

    // Escape closes the search overlay — the footer advertises "esc close" but
    // nothing wired it. Inline/embedded mode opts out (it isn't a dismissible
    // overlay). Covers both the modal and the anchored dropdown.
    useEffect(() => {
        if (!isOpen || inline) return;
        const onKeyDown = (e: KeyboardEvent) => {
            if (e.key === 'Escape') onClose();
        };
        document.addEventListener('keydown', onKeyDown);
        return () => document.removeEventListener('keydown', onKeyDown);
    }, [isOpen, inline, onClose]);

    const handleSendMessage = (content: string) => {
        setQuery(content);
        const fakeEvent = {
            preventDefault: () => {},
            _directQuery: content,
        };
        setTimeout(() => {
            onSubmit(fakeEvent);
        }, 0);
    };

    const handleMobileScroll = (e: React.UIEvent<HTMLDivElement>) => {
        const scrollTop = (e.currentTarget as HTMLDivElement).scrollTop;
        if (scrollTop > 50 && isBottomSheetExpanded) {
            setIsBottomSheetExpanded(false);
        }
    };

    const handleMessageIndexChange = (index: number) => {
        setMessageIndex(index);
        if (mobileResultsRef.current) {
            mobileResultsRef.current.scrollTop = 0;
        }
    };

    if (!isOpen) {
        return null;
    }

    const privacySettingsProps: Omit<SearchPrivacySettingsProps, 'isMobile' | 'onResetChat'> = {
        sessionId,
        privacyPolicyUrl,
        onOpenSupport,
        consentEnabled,
        onToggleConsent,
        consentDisabled,
    };

    // Desktop Layout
    if (!isMobile) {
        const modalBody = (
                <div
                    ref={modalRef}
                    className={inline
                        ? 'omniguide-search-inline'
                        : `omniguide-modal__overlay ${isCompactMode ? 'omniguide-modal__overlay--compact' : ''} ${anchoredActive ? 'omniguide-modal__overlay--anchored' : ''}`}
                    style={!inline && anchoredActive ? anchorStyle : undefined}
                    role="dialog"
                    aria-modal={inline || anchoredActive ? undefined : 'true'}
                    aria-label="AI Search"
                >
                    {/* Inline mode has no modal header, so it gets its own close
                        (X) in the top-right of the embedded panel. */}
                    {inline && (
                        <button
                            type="button"
                            className="omniguide-search-inline__close"
                            onClick={onClose}
                            aria-label="Close"
                        >
                            <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                <line x1="18" y1="6" x2="6" y2="18"></line>
                                <line x1="6" y1="6" x2="18" y2="18"></line>
                            </svg>
                        </button>
                    )}
                    {/* Inline mode hides the modal header + footer (below) so
                        only the split-panel shows; the compact searchbar stays. */}
                    {isCompactMode ? (
                        <div className="omniguide-modal__searchbar">
                            <SearchChatInput
                                onSendMessage={handleSendMessage}
                                onValueChange={setLiveQuery}
                                isLoading={isLoading}
                                isMobile={false}
                                topSearch={true}
                                connectionStatus={connectionStatus}
                                reconnectInfo={reconnectInfo}
                            />
                            <button
                                onClick={onClose}
                                className="omniguide-modal__close-btn omniguide-modal__close-btn--inline"
                                data-hovered={closeButtonHovered}
                                onMouseEnter={() => setCloseButtonHovered(true)}
                                onMouseLeave={() => setCloseButtonHovered(false)}
                                aria-label="Close search"
                            >
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <line x1="18" y1="6" x2="6" y2="18"></line>
                                    <line x1="6" y1="6" x2="18" y2="18"></line>
                                </svg>
                            </button>
                        </div>
                    ) : (!inline && (
                        <div className="omniguide-modal__header">
                            <span className="omniguide-modal__header-icon" aria-hidden="true">
                                {searchIcon || <DefaultAISearchIcon />}
                            </span>
                            {(title || subtitle) && (
                                <div className="omniguide-modal__header-titles">
                                    {title && <h1 className="omniguide-modal__header-title">{title}</h1>}
                                    {subtitle && <span className="omniguide-modal__header-sub">{subtitle}</span>}
                                </div>
                            )}
                            <span className="omniguide-modal__header-spacer" />
                            <span className="omniguide-modal__header-pill">
                                <span className="omniguide-modal__header-led" aria-hidden="true" />
                                AI-assisted
                            </span>
                            {(supportHref || onOpenSupport) && (
                                supportHref ? (
                                    <a
                                        href={supportHref}
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="omniguide-modal__header-talk"
                                        onClick={onOpenSupport}
                                    >
                                        {supportLabel}
                                        <svg viewBox="0 0 16 16" width="13" height="13" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true"><path d="M3 8h9M8.5 4l4 4-4 4" /></svg>
                                    </a>
                                ) : (
                                    <button
                                        type="button"
                                        className="omniguide-modal__header-talk"
                                        onClick={onOpenSupport}
                                    >
                                        {supportLabel}
                                        <svg viewBox="0 0 16 16" width="13" height="13" fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round" aria-hidden="true"><path d="M3 8h9M8.5 4l4 4-4 4" /></svg>
                                    </button>
                                )
                            )}
                            <button
                                onClick={onClose}
                                className="omniguide-modal__close-btn"
                                data-hovered={closeButtonHovered}
                                onMouseEnter={() => setCloseButtonHovered(true)}
                                onMouseLeave={() => setCloseButtonHovered(false)}
                                aria-label="Close search"
                            >
                                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                                    <line x1="18" y1="6" x2="6" y2="18"></line>
                                    <line x1="6" y1="6" x2="18" y2="18"></line>
                                </svg>
                            </button>
                        </div>
                    ))}

                    <div className="omniguide-split-panel">
                        <SearchChatPanel
                            messages={messages}
                            onSendMessage={handleSendMessage}
                            isLoading={isLoading}
                            isMobile={false}
                            isOpen={isOpen}
                            pipelineStatus={pipelineStatus}
                            onIntentAnswer={onIntentAnswer}
                            onCustomIntentAnswer={handleSendMessage}
                            onClarificationAnswer={onClarificationAnswer}
                            onCustomClarificationAnswer={handleSendMessage}
                            onResetChat={onResetChat}
                            currentMessageIndex={currentMessageIndex}
                            onMessageIndexChange={handleMessageIndexChange}
                            isCompactMode={isCompactMode}
                            hideInput={isCompactMode}
                            liveQuery={liveQuery}
                            typeahead={typeahead}
                            aiSearchStoreUrl={aiSearchStoreUrl}
                            welcomeText={welcomeText}
                            siteName={title}
                            seedQuestions={seedQuestions}
                            fetchProductUrls={fetchProductUrls}
                            conversationId={conversationId}
                            FeedbackWidgetComponent={FeedbackWidgetComponent}
                            privacySettingsProps={privacySettingsProps}
                            defaultSearchExamples={defaultSearchExamples}
                            connectionStatus={connectionStatus}
                            onRetryConnection={onRetryConnection}
                            reconnectInfo={reconnectInfo}
                            onScrollForMoreTapped={onScrollForMoreTapped}
                            onScrollStarted={onScrollStarted}
                            onInlineProductLinkClick={onInlineProductLinkClick}
                        />

                        {!isCompactMode && (
                            <SearchResultsPanel
                                sources={sources as SearchResultsPanelProps['sources']}
                                trackProductClick={trackProductClick}
                                trackCategoryClick={trackCategoryClick}
                                trackContentClick={trackContentClick}
                                messageId={messageId ?? undefined}
                                queryContext={queryContext ?? undefined}
                                isLoading={isLoading}
                                aiSearchStoreUrl={aiSearchStoreUrl}
                                fallbackProductImage={fallbackProductImage}
                                fallbackBlogImage={fallbackBlogImage}
                                showProductTags={showProductTags}
                                zeroPriceDisplay={zeroPriceDisplay}
                                intent={intent}
                                relatedContentFirstForQuestions={relatedContentFirstForQuestions}
                            />
                        )}
                    </div>

                    {!inline && !isCompactMode && (
                        <div className="omniguide-modal__foot">
                            <span className="omniguide-modal__foot-note">Verify details on the linked product pages.</span>
                        </div>
                    )}
                </div>
        );

        // Inline mode: render in-flow (no overlay/backdrop) via a portal into
        // the host target, so the split-panel sits beneath the host element.
        if (inline) {
            const target = typeof inlineTarget === 'string'
                ? document.querySelector(inlineTarget)
                : (inlineTarget ?? null);
            return target ? createPortal(modalBody, target) : null;
        }

        return (
            <>
                {!anchoredActive && (
                    <div className="omniguide-modal__backdrop" onClick={onClose} />
                )}
                {modalBody}
            </>
        );
    }

    // Mobile Layout with Bottom Sheet
    return (
        <div
            ref={modalRef}
            className="omniguide-modal__overlay omniguide-modal__overlay--fullscreen"
            role="dialog"
            aria-modal="true"
            aria-label="AI Search"
        >
            <button
                onClick={onClose}
                className="omniguide-modal__close-btn omniguide-modal__close-btn--mobile"
                aria-label="Close search"
            >
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                    <line x1="18" y1="6" x2="6" y2="18"></line>
                    <line x1="6" y1="6" x2="18" y2="18"></line>
                </svg>
            </button>

            <div className="omniguide-mobile-container">
                <div
                    className={`omniguide-mobile-results-bg ${messages.length === 0 ? 'omniguide-mobile-results-bg--initial' : ''} ${isBottomSheetExpanded ? 'omniguide-mobile-results-bg--sheet-expanded' : 'omniguide-mobile-results-bg--sheet-collapsed'}`}
                    ref={mobileResultsRef}
                    onScroll={handleMobileScroll}
                    onFocus={() => {
                        if (isBottomSheetExpanded) {
                            setIsBottomSheetExpanded(false);
                        }
                    }}
                >
                    <SearchMobileResultsPanel
                        messages={messages}
                        trackProductClick={trackProductClick}
                        trackCategoryClick={trackCategoryClick}
                        trackContentClick={trackContentClick}
                        currentSectionIndex={currentSectionIndex}
                        isLoading={isLoading}
                        currentQuestion={qaPairs[currentMessageIndex]?.userMessage?.content || ''}
                        isBottomSheetExpanded={isBottomSheetExpanded}
                        aiSearchStoreUrl={aiSearchStoreUrl}
                        fallbackProductImage={fallbackProductImage}
                        fallbackCategoryImage={fallbackCategoryImage}
                        fallbackBlogImage={fallbackBlogImage}
                        showProductTags={showProductTags}
                        zeroPriceDisplay={zeroPriceDisplay}
                        relatedContentFirstForQuestions={relatedContentFirstForQuestions}
                    />
                </div>

                <div
                    className={`omniguide-mobile-bottom-sheet ${isBottomSheetExpanded ? 'omniguide-mobile-bottom-sheet--expanded' : 'omniguide-mobile-bottom-sheet--collapsed'} ${messages.length === 0 ? 'omniguide-mobile-bottom-sheet--initial' : ''}`}
                    onClick={() => {
                        if (!isBottomSheetExpanded) {
                            setIsBottomSheetExpanded(true);
                        }
                    }}
                    onFocus={() => {
                        if (!isBottomSheetExpanded) {
                            setIsBottomSheetExpanded(true);
                        }
                    }}
                >
                    <div className="omniguide-mobile-bottom-sheet__handle">
                        <div className="omniguide-mobile-bottom-sheet__handle-bar"></div>
                    </div>

                    <SearchChatPanel
                        messages={messages}
                        onSendMessage={handleSendMessage}
                        isLoading={isLoading}
                        isMobile={true}
                        isOpen={isOpen}
                        isCollapsed={!isBottomSheetExpanded}
                        onCollapseToggle={() => setIsBottomSheetExpanded(true)}
                        pipelineStatus={pipelineStatus}
                        onIntentAnswer={onIntentAnswer}
                        onCustomIntentAnswer={handleSendMessage}
                        onClarificationAnswer={onClarificationAnswer}
                        onCustomClarificationAnswer={handleSendMessage}
                        onResetChat={onResetChat}
                        welcomeText={welcomeText}
                        siteName={title}
                        seedQuestions={seedQuestions}
                        currentMessageIndex={currentMessageIndex}
                        onMessageIndexChange={handleMessageIndexChange}
                        fetchProductUrls={fetchProductUrls}
                        conversationId={conversationId}
                        FeedbackWidgetComponent={FeedbackWidgetComponent}
                        defaultSearchExamples={defaultSearchExamples}
                        connectionStatus={connectionStatus}
                        onRetryConnection={onRetryConnection}
                        reconnectInfo={reconnectInfo}
                        onScrollForMoreTapped={onScrollForMoreTapped}
                        onScrollStarted={onScrollStarted}
                        onInlineProductLinkClick={onInlineProductLinkClick}
                        aiSearchStoreUrl={aiSearchStoreUrl}
                        hideMobileAskBox={hideMobileAskBox}
                        mobileAskPlaceholder={mobileAskPlaceholder}
                    />
                </div>

                <SearchPrivacySettings
                    isMobile={true}
                    onResetChat={onResetChat}
                    sessionId={sessionId}
                    privacyPolicyUrl={privacyPolicyUrl}
                    onOpenSupport={onOpenSupport}
                    supportHref={supportHref}
                    supportLabel={supportLabel}
                    consentEnabled={consentEnabled}
                    onToggleConsent={onToggleConsent}
                    consentDisabled={consentDisabled}
                />
            </div>
        </div>
    );
};
