/**
 * BCSearchContainer — Main search container for BigCommerce themes.
 *
 * Ported from theme `search/ai-search.jsx`.
 * Composes all hooks, renders SearchUI from omniguide-react.
 * Replaces per-theme container components.
 */

import React, { useState, useRef, useEffect, useMemo, useCallback } from 'react';
import { createScopedLogger, setRegistrySessionStart, emitRecommendations } from '@swiftotter/omniguide-core';
import {
  SearchUI,
  useOmniguideContext,
} from '@swiftotter/omniguide-react';

import { fetchProductUrlsBySkus } from '../services/productUrls.js';
import { useSessionInit } from '../hooks/useSessionInit.js';
import { useBCSearchChat } from '../hooks/useBCSearchChat.js';
import { useAnalyticsTracking } from '../hooks/useAnalyticsTracking.js';
import { useUserConsent } from '../hooks/useUserConsent.js';
import { useFeedbackWidget } from '../hooks/useFeedbackWidget.js';
import { buildBCHydrationConfig } from '../hooks/buildHydrationConfig.js';

const log = createScopedLogger('BCSearchContainer');

// ── Constants ──────────────────────────────────────────────────────

const SEARCH_HASH = '#!/search';

// ── Component ──────────────────────────────────────────────────────

export function BCSearchContainer(): JSX.Element | null {
  const { config, platformAdapter, consentService } =
    useOmniguideContext();

  const {
    websiteId,
    aiSearchStoreUrl,
    callbacks,
    consent,
    fallbackImages,
    ui,
  } = config;

  // ── Modal State ────────────────────────────────────────────────

  const [isOpen, setIsOpen] = useState(() => {
    return (
      window.location.hash === SEARCH_HASH &&
      (callbacks?.isFeatureEnabled?.() ?? true)
    );
  });

  const sessionStartRef = useRef<number | null>(null);

  // True when the search was opened from the category-guide "ask a question"
  // (renders the inline split-panel beneath the teaser instead of a modal).
  const [inlineOpen, setInlineOpen] = useState(false);

  const [isConversational, setIsConversational] = useState(() => {
    const storedMode = localStorage.getItem('aiSearch');
    if (storedMode !== null) return storedMode === 'true';
    return true;
  });

  // ── Hooks ──────────────────────────────────────────────────────

  const { sessionId, setSessionId: _setSessionId, welcomeText, seedQuestions } =
    useSessionInit();

  const {
    trackMessageSent,
    trackProductClick,
    trackCategoryClick,
    trackContentClick,
    trackFeedback,
    trackComponentClose,
    trackSearchOpened,
    trackQuestionAnswered,
    trackRecommendationProvided,
    trackStartOver,
    trackScrollForMore,
    trackScrollStarted,
    trackRecProductClick,
    trackInlineProductLink,
  } = useAnalyticsTracking({ websiteId });

  const handleFeedbackSubmitted = useCallback(({ entityId, vote }: { entityId: string; vote: number }) => {
    trackFeedback({
      messageId: entityId,
      feedbackType: vote > 0 ? 'thumbs_up' : 'thumbs_down',
      turnNumber: 0,
    });
  }, [trackFeedback]);

  const FeedbackWidgetComponent = useFeedbackWidget({
    onFeedbackSubmitted: handleFeedbackSubmitted,
  });

  const {
    messages,
    query,
    setQuery,
    isLoading,
    conversationId,
    sendMessage,
    sendIntentAnswer,
    sendClarificationAnswer,
    handleResetChat,
    pipelineStatus,
    connectionStatus,
    hasAttemptedConnection,
    reconnectInfo,
    connect,
    error: _chatError,
  } = useBCSearchChat({
    trackMessageSent,
    trackQuestionAnswered,
    trackRecommendationProvided,
    trackStartOver,
    autoConnect: false,
    sessionId,
  });

  // Consent state (two-tier model)
  const { analytics, advertising, websiteConsent, omniguideConsent } = useUserConsent();
  const consentEnabled = analytics && advertising;

  const handleToggleConsent = useCallback(async () => {
    try {
      if (consentService && sessionId && websiteConsent) {
        await consentService.updatePreferences(sessionId, !omniguideConsent);
      }
    } catch (error) {
      log.error('Failed to update consent preferences:', error);
    }
  }, [consentService, sessionId, websiteConsent, omniguideConsent]);

  // ── Product URL Fetching ───────────────────────────────────────

  const hydrationConfig = useMemo(
    () => buildBCHydrationConfig(config, platformAdapter),
    [config, platformAdapter],
  );

  const fetchProductUrls = useCallback(
    (skus: string[]) => fetchProductUrlsBySkus(skus, hydrationConfig),
    [hydrationConfig],
  );

  // ── URL Hash Sync ──────────────────────────────────────────────

  // The inline "ask a question" panel (source: category_guide_teaser) is an
  // in-flow surface, not a route — it must NOT push the #!/search hash the
  // modal/full-screen search uses for deep-linking and back-button close.
  const isInlineSearch = inlineOpen && !!ui?.inlineSearchTarget;

  useEffect(() => {
    if (isOpen && !isInlineSearch) {
      if (window.location.hash !== SEARCH_HASH) {
        window.history.pushState(null, '', SEARCH_HASH);
      }
    } else {
      if (window.location.hash === SEARCH_HASH) {
        window.history.pushState(
          null,
          '',
          window.location.pathname + window.location.search,
        );
      }
    }
  }, [isOpen, isInlineSearch]);

  // Listen for browser back/forward navigation
  useEffect(() => {
    const handleHashChange = () => {
      const shouldBeOpen =
        window.location.hash === SEARCH_HASH &&
        (callbacks?.isFeatureEnabled?.() ?? true);
      setIsOpen(shouldBeOpen);
      if (!shouldBeOpen) {
        window.dispatchEvent(new CustomEvent('closeAISearch', { detail: { websiteId } }));
      }
    };

    window.addEventListener('hashchange', handleHashChange);
    return () => window.removeEventListener('hashchange', handleHashChange);
  }, [callbacks, websiteId]);

  // ── Session Timer + WebSocket Connect ──────────────────────────

  useEffect(() => {
    if (isOpen && sessionId && !sessionStartRef.current) {
      sessionStartRef.current = Date.now();
      setRegistrySessionStart(websiteId, Date.now());
      connect().catch((err: unknown) => {
        log.error('WebSocket connect failed:', err);
        log.debug('Connection context:', {
          websiteId,
          apiBaseUrl: config.apiBaseUrl,
          sessionId: sessionId ? `${sessionId.substring(0, 20)}...` : '(none)',
          origin: window.location.origin,
          aiSearchStoreUrl,
        });
      });
    }
    if (!isOpen && sessionStartRef.current) {
      sessionStartRef.current = null;
    }
  }, [isOpen, sessionId, connect, websiteId, config.apiBaseUrl, aiSearchStoreUrl]);

  // ── Mode Persistence + Event Listeners ─────────────────────────

  useEffect(() => {
    localStorage.setItem('aiSearch', isConversational.toString());

    const handleSearchOpen = (event: CustomEvent) => {
      // Filter: only respond to our own instance's events
      if (event.detail?.websiteId && event.detail.websiteId !== websiteId) return;
      // Opened from the category-guide "ask a question" → render the search
      // in-flow (inline split-panel) beneath the teaser rather than as a modal.
      setInlineOpen(event.detail?.source === 'category_guide_teaser');
      setIsOpen(true);
      trackSearchOpened({
        source: event.detail?.source || 'search_button',
        page_type: window.location.pathname.includes('/products/')
          ? 'product'
          : window.location.pathname.includes('/category/')
            ? 'category'
            : 'other',
      });

      if (event.detail?.query) {
        setQuery(event.detail.query);
      }
    };

    window.addEventListener(
      'openAISearch',
      handleSearchOpen as EventListener,
    );

    const handleEscape = (e: KeyboardEvent) => {
      if (e.key === 'Escape' && isOpen) {
        setIsOpen(false);
        window.dispatchEvent(new CustomEvent('closeAISearch', { detail: { websiteId } }));
      }
    };
    document.addEventListener('keydown', handleEscape);

    return () => {
      window.removeEventListener(
        'openAISearch',
        handleSearchOpen as EventListener,
      );
      document.removeEventListener('keydown', handleEscape);
    };
  }, [isOpen, setQuery, isConversational, trackSearchOpened, websiteId]);

  // Publish the latest answer's product recommendations to the recommendation
  // bus so a PLP can render them as a filtered subset (client override). Carries
  // display data (name/price/image/url) so the consumer needs no extra fetch.
  useEffect(() => {
    const latest = messages.find(
      (m) => m.role === 'assistant' && Array.isArray(m.sources) &&
        (m.sources as Array<{ type?: string; data?: unknown }>).some((s) => s?.type === 'product' && s.data),
    );
    if (!latest) return;
    const products = (latest.sources as Array<{ type?: string; data?: Record<string, unknown> }>)
      .filter((s) => s?.type === 'product' && s.data)
      .map((s, i) => {
        const d = s.data as Record<string, unknown>;
        const brand = typeof d['brand'] === 'object'
          ? (d['brand'] as { name?: string })?.name
          : (d['product_line'] as string) ?? (d['brand'] as string);
        return {
          sku: String(d['sku'] ?? d['id'] ?? d['entityId'] ?? ''),
          id: (d['id'] ?? d['entityId']) as string | number | undefined,
          name: (d['name'] ?? d['display_name']) as string | undefined,
          brand,
          url: (d['url'] ?? d['path']) as string | undefined,
          image_url: (d['imageUrl'] ?? d['image_url']) as string | undefined,
          price: d['price'] as number | string | undefined,
          retail_price: (d['originalPrice'] ?? d['retail_price']) as number | string | undefined,
          matchPct: d['matchPct'] as number | undefined,
          rank: (d['rank'] as number | undefined) ?? i + 1,
        };
      })
      .filter((p) => p.sku || p.name);
    if (products.length) emitRecommendations({ page: 'plp', products, source: 'search' });
  }, [messages]);

  // ── Support + Modal Callbacks ──────────────────────────────────

  const handleOpenSupport = useCallback(() => {
    callbacks?.onOpenSupport?.();
  }, [callbacks]);

  const handleModalOpen = useCallback(() => {
    callbacks?.onModalOpen?.();
  }, [callbacks]);

  const handleModalClose = useCallback(() => {
    callbacks?.onModalClose?.();
  }, [callbacks]);

  // ── Handlers ───────────────────────────────────────────────────

  const handleSubmit = useCallback(
    (e: { preventDefault: () => void; _directQuery?: string }) => {
      e.preventDefault();
      const searchQuery = e._directQuery || query;
      if (!searchQuery.trim() || isLoading) return;

      if (isConversational) {
        sendMessage(searchQuery);
      } else {
        window.location.href = `/search.php?search_query=${encodeURIComponent(searchQuery)}`;
      }
      setQuery('');
    },
    [query, isLoading, isConversational, sendMessage, setQuery],
  );

  const handleModeToggle = useCallback(() => {
    setIsConversational((prev) => !prev);
  }, []);

  const handleClose = useCallback(() => {
    if (trackComponentClose && sessionStartRef.current) {
      const duration = Date.now() - sessionStartRef.current;
      trackComponentClose({
        sessionDurationMs: duration,
        totalMessages: messages.length,
      });
    }

    setIsOpen(false);
    window.dispatchEvent(new CustomEvent('closeAISearch', { detail: { websiteId } }));
  }, [trackComponentClose, messages.length, websiteId]);

  // Adapt tracking callbacks to Record<string, unknown> expected by SearchUI
  const adaptedTrackProductClick = useCallback(
    (data: Record<string, unknown>) => {
      trackProductClick(data as Parameters<typeof trackProductClick>[0]);
      trackRecProductClick({
        sku: String(data['productSku'] || ''),
        recSource: 'chat_result',
        recPageArea: 'header',
        recPosition: typeof data['position'] === 'number' ? data['position'] : undefined,
        messageId: typeof data['messageId'] === 'string' ? data['messageId'] : undefined,
      });
    },
    [trackProductClick, trackRecProductClick],
  );
  const adaptedTrackCategoryClick = useCallback(
    (data: Record<string, unknown>) => trackCategoryClick(data as Parameters<typeof trackCategoryClick>[0]),
    [trackCategoryClick],
  );
  const adaptedTrackContentClick = useCallback(
    (data: Record<string, unknown>) => trackContentClick(data as Parameters<typeof trackContentClick>[0]),
    [trackContentClick],
  );

  const handleInlineProductLinkClick = useCallback(
    (data: { sku: string; href: string; messageId?: string; queryContext: string }) => {
      trackInlineProductLink({
        sku: data.sku,
        productUrl: data.href,
        messageId: data.messageId,
        recPageArea: 'header',
        queryContext: data.queryContext,
      });
    },
    [trackInlineProductLink],
  );

  // Adapt intent/clarification answers to accept string | number
  const handleScrollForMoreTapped = useCallback(
    (messageId: string) => trackScrollForMore({ messageId }),
    [trackScrollForMore],
  );
  const handleScrollStarted = useCallback(
    (messageId: string) => trackScrollStarted({ messageId }),
    [trackScrollStarted],
  );

  const adaptedSendIntentAnswer = useCallback(
    (answerText: string, answerId: string | number, options?: Record<string, unknown>) => {
      sendIntentAnswer(answerText, String(answerId), options as { isOtherAnswer?: boolean; otherAnswerText?: string });
    },
    [sendIntentAnswer],
  );
  const adaptedSendClarificationAnswer = useCallback(
    (answerText: string, optionId: string | number, paramName: string) => {
      sendClarificationAnswer(answerText, String(optionId), paramName);
    },
    [sendClarificationAnswer],
  );

  // ── Render ─────────────────────────────────────────────────────

  return (
    <SearchUI
      isOpen={isOpen}
      onClose={handleClose}
      onResetChat={handleResetChat}
      onSubmit={handleSubmit}
      query={query}
      setQuery={setQuery}
      messages={messages}
      isLoading={isLoading}
      conversationId={conversationId ?? undefined}
      isConversational={isConversational}
      onModeToggle={handleModeToggle}
      trackProductClick={adaptedTrackProductClick}
      trackCategoryClick={adaptedTrackCategoryClick}
      trackContentClick={adaptedTrackContentClick}
      pipelineStatus={pipelineStatus}
      onIntentAnswer={adaptedSendIntentAnswer}
      onClarificationAnswer={adaptedSendClarificationAnswer}
      connectionStatus={hasAttemptedConnection ? connectionStatus : undefined}
      onRetryConnection={connect}
      reconnectInfo={reconnectInfo}
      welcomeText={welcomeText}
      seedQuestions={seedQuestions}
      title={ui?.searchTitle ?? 'Smart Shopping'}
      subtitle={ui?.searchSubtitle ?? 'Shopping Advisor'}
      searchIcon={ui?.searchIconUrl ? <img className="omniguide-modal__header-icon-img" src={ui.searchIconUrl} alt="" /> : undefined}
      aiSearchStoreUrl={aiSearchStoreUrl}
      fallbackProductImage={fallbackImages?.product}
      fallbackCategoryImage={fallbackImages?.category}
      fallbackBlogImage={fallbackImages?.blog}
      fetchProductUrls={fetchProductUrls}
      sessionId={sessionId ?? ''}
      FeedbackWidgetComponent={FeedbackWidgetComponent}
      onOpenSupport={callbacks?.onOpenSupport ? handleOpenSupport : undefined}
      supportHref={ui?.supportHref}
      supportLabel={ui?.supportLabel}
      onModalOpen={handleModalOpen}
      onModalClose={handleModalClose}
      privacyPolicyUrl={consent?.privacyPolicyUrl ?? '/privacy-policy'}
      defaultSearchExamples={ui?.searchExampleQuestions}
      consentEnabled={consent?.enabled ? consentEnabled : undefined}
      onToggleConsent={consent?.enabled ? handleToggleConsent : undefined}
      consentDisabled={consent?.enabled ? !websiteConsent : undefined}
      showProductTags={config.features?.productTags !== false}
      zeroPriceDisplay={ui?.zeroPriceDisplay}
      relatedContentFirstForQuestions={ui?.search?.relatedContentFirstForQuestions ?? true}
      onScrollForMoreTapped={handleScrollForMoreTapped}
      onScrollStarted={handleScrollStarted}
      onInlineProductLinkClick={handleInlineProductLinkClick}
      anchored={ui?.anchoredSearch}
      anchorSelector={ui?.searchAnchorSelector}
      inline={inlineOpen && !!ui?.inlineSearchTarget}
      inlineTarget={ui?.inlineSearchTarget}
      typeahead={ui?.typeahead}
      hideMobileAskBox={config.features?.hideMobileAskBox === true}
    />
  );
}
