/**
 * Computes sources and section index for the currently viewed message.
 * Used by AISearchUI to sync ResultsPanel with ChatPanel navigation.
 */

import { useMemo } from 'react';
import type { QAPair, UseMessageSourcesReturn } from '../types.js';

export function useMessageSources(
  qaPairs: QAPair[],
  currentMessageIndex: number,
): UseMessageSourcesReturn {
  // Calculate section index for MobileResultsPanel based on current qaPairs index
  const currentSectionIndex = useMemo(() => {
    let sectionIdx = 0;
    for (let i = 0; i <= currentMessageIndex && i < qaPairs.length; i++) {
      const pair = qaPairs[i];
      if (pair && pair.type !== 'thinking' && pair.assistantMessage?.sources && pair.assistantMessage.sources.length > 0) {
        if (i === currentMessageIndex) {
          return sectionIdx;
        }
        sectionIdx++;
      }
    }
    return Math.max(0, sectionIdx - 1);
  }, [currentMessageIndex, qaPairs]);

  // Get sources for the currently viewed message
  const { sources, messageId, queryContext, intent } = useMemo(() => {
    if (qaPairs.length === 0 || currentMessageIndex >= qaPairs.length) {
      return { sources: [] as unknown[], messageId: null, queryContext: null, intent: null };
    }

    const pair = qaPairs[currentMessageIndex];
    if (!pair || pair.type === 'thinking' || !pair.assistantMessage) {
      return { sources: [] as unknown[], messageId: null, queryContext: null, intent: null };
    }

    const meta = pair.assistantMessage.metadata;
    const metaIntent = meta && typeof meta['intent'] === 'string' ? (meta['intent'] as string) : null;

    return {
      sources: pair.assistantMessage.sources ?? [],
      messageId: pair.assistantMessage.id,
      queryContext: pair.assistantMessage.queryContext ?? null,
      intent: metaIntent,
    };
  }, [qaPairs, currentMessageIndex]);

  return { sources, messageId, queryContext, currentSectionIndex, intent };
}
